GameFitnessEquip = {}

function GameFitnessEquip:onButtonClick(player, itemId)
    for _, Value in pairs(player.shopFitnessEquip) do
        if Value.id == itemId then
            if Value.status == Define.ItemBuyStatus.Unlock then
                self:onFitnessEquipBuy(player, itemId, true)
            elseif Value.status == Define.ItemBuyStatus.Buy then
                self:onFitnessEquipUsed(player, itemId)
            elseif Value.status == Define.ItemBuyStatus.Used then
                self:onFitnessEquipUnload(player, itemId)
            end
        end
    end
end

function GameFitnessEquip:onFitnessEquipBuy(player, itemId, needMoney)
    --�������ò��ɹ���
    if itemId == 111 then
        return
    end
    
    local equip = FitnessEquipConfig:getFitnessEquipConfig(itemId)
    if equip == nil then
        return
    end
    if not needMoney then
        self:onBuySuccess(player, itemId)
        return
    end
    if equip.moneyType == Define.MoneyType.SLGolds then

        if player.property.gold >= BigNum.new(string.format("%f", equip.price)) then
            player.property:changeGold(-equip.price)
            self:onBuySuccess(player, itemId)
        else
            HostApi.sendCommonTip(player.rakssid, "gold_enough")
        end
    end

    if equip.moneyType == Define.MoneyType.DiamondGolds1 or equip.moneyType == Define.MoneyType.DiamondGolds2 then
        PayHelper.payDiamondsSync(player.userId, equip.id, equip.price, function(player)
            self:onBuySuccess(player, itemId)
        end, nil)
    end

    ReportUtil.reportFitnessEquipBuy(player, itemId)
end
function GameFitnessEquip:onBuySuccess(player, itemId)
    local data = {}
    local usedId = 0
    local unlockId = 0

    --Used to Buy
    for _, Value in pairs(player.shopFitnessEquip) do
        if Value.status == Define.ItemBuyStatus.Used then
            Value.status = Define.ItemBuyStatus.Buy
            table.insert(data, {
                Id = Value.id,
                Status = Value.status
            })
        end
    end

    --to Used
    for _, Value in pairs(player.shopFitnessEquip) do
        if Value.id == itemId then
            Value.status = Define.ItemBuyStatus.Used
            usedId = Value.id
            table.insert(data, {
                Id = Value.id,
                Status = Value.status
            })
        end
    end

    --Lock to Unlock
    for _, Value in pairs(player.shopFitnessEquip) do
        local equip = FitnessEquipConfig:getFitnessEquipConfig(Value.id)
        if equip and equip.unlock == itemId and Value.status == Define.ItemBuyStatus.Lock then
            Value.status = Define.ItemBuyStatus.Unlock
            unlockId = Value.id
            table.insert(data, {
                Id = Value.id,
                Status = Value.status
            })
        end
    end

    table.sort(player.shopFitnessEquip, function(a, b)
        return FitnessEquipConfig:getFitnessEquipSortId(a.id) < FitnessEquipConfig:getFitnessEquipSortId(b.id)
    end)

    local equip = FitnessEquipConfig:getFitnessEquipConfig(itemId)
    if equip.moneyType == Define.MoneyType.DiamondGolds1 or equip.moneyType == Define.MoneyType.DiamondGolds2 then
        local itemSortId = FitnessEquipConfig:getFitnessEquipSortId(itemId)
        for i = 1, #player.shopFitnessEquip do
            local Value = player.shopFitnessEquip[i]
            local valueSortId = FitnessEquipConfig:getFitnessEquipSortId(Value.id)
            if valueSortId < itemSortId and Value.status == Define.ItemBuyStatus.Lock then
                Value.status = Define.ItemBuyStatus.Unlock
                table.insert(data, {
                    Id = Value.id,
                    Status = Value.status
                })
            end
            --if valueSortId > itemSortId and Value.status == Define.ItemBuyStatus.Lock then
            --    Value.status = Define.ItemBuyStatus.Unlock
            --    table.insert(data, {
            --        Id = Value.id,
            --        Status = Value.status
            --    })
            --    break
            --end
        end
    end

    player.property:changeFitnessEquipId(usedId, unlockId)
    ShopManager:senderFitnessEquipInfo(player, data)
    GameFitnessEquip:shareDataToTokenFitnessEquip(player, data)

    local nextNeedSelect = FitnessEquipConfig:getNextNeedSelectById(equip.id)
    if nextNeedSelect then
        GamePacketSender:sendShopItemSelectStatus(player.rakssid, Define.ShopKind.FitnessEquip, nextNeedSelect.id)
    end
end

function GameFitnessEquip:onFitnessEquipUsed(player, itemId)
    local data = {}
    for _, Value in pairs(player.shopFitnessEquip) do
        if Value.status == Define.ItemBuyStatus.Used then
            Value.status = Define.ItemBuyStatus.Buy
            table.insert(data, {
                Id = Value.id,
                Status = Value.status
            })
        end
    end

    for _, Value in pairs(player.shopFitnessEquip) do
        if Value.id == itemId then
            Value.status = Define.ItemBuyStatus.Used
            table.insert(data, {
                Id = Value.id,
                Status = Value.status
            })
        end
    end

    player.property:changeFitnessEquipId(itemId, nil)

    ShopManager:senderFitnessEquipInfo(player, data)
    GameFitnessEquip:shareDataToTokenFitnessEquip(player, data)
end

function GameFitnessEquip:onFitnessEquipUnload(player, itemId)

end

function GameFitnessEquip:updateShopFitnessEquip(player)
    if not player then
        return
    end

    for _, setting in pairs(FitnessEquipConfig.settings) do
        local find = false
        for _, data in pairs(player.shopFitnessEquip) do
            if data.id == setting.id then
                find = true
                break
            end
        end

        if not find then
            if FitnessEquipConfig:isPayFitnessEquip(setting.id) then
                local payConfig = FitnessEquipConfig:getPayFitnessEquipConfig(setting.id)
                if payConfig and player.property.advancedLevel >= payConfig.unlockAdvancedLevel then
                    table.insert(player.shopFitnessEquip, {
                        id = setting.id,
                        status = Define.ItemBuyStatus.Unlock
                    })
                else
                    table.insert(player.shopFitnessEquip, {
                        id = setting.id,
                        status = Define.ItemBuyStatus.Lock
                    })
                end
            else
                table.insert(player.shopFitnessEquip, {
                    id = setting.id,
                    status = Define.ItemBuyStatus.Lock
                })
            end
        end
    end
end

function GameFitnessEquip:initFitnessEquipItem(player)
    if #player.shopFitnessEquip ~= 0 then
        GameFitnessEquip:updateShopFitnessEquip(player)
        return
    end

    table.sort(FitnessEquipConfig.settings, function(a, b)
        return a.sortId < b.sortId
    end)

    local i = 1
    local itemId = 0
    for _, Value in pairs(FitnessEquipConfig.settings) do
        if i == 1 then
            table.insert(player.shopFitnessEquip, {
                id = Value.id,
                status = Define.ItemBuyStatus.Used
            })
            itemId = Value.id
        else
            table.insert(player.shopFitnessEquip, {
                id = Value.id,
                status = Define.ItemBuyStatus.Lock
            })
        end
        i = i + 1
    end

    table.sort(player.shopFitnessEquip, function(a, b)
        return FitnessEquipConfig:getFitnessEquipSortId(a.id) < FitnessEquipConfig:getFitnessEquipSortId(b.id)
    end)

    local nextUnlockItemId = nil
    for _, Value in pairs(player.shopFitnessEquip) do
        local equip = FitnessEquipConfig:getFitnessEquipConfig(Value.id)
        if equip and equip.unlock == itemId and Value.status == Define.ItemBuyStatus.Lock then
            nextUnlockItemId = equip.id
            Value.status = Define.ItemBuyStatus.Unlock
        end
    end
    
    --��֤������һ������
    if not nextUnlockItemId then
        for _, Value in pairs(player.shopFitnessEquip) do
            if Value.status == Define.ItemBuyStatus.Lock then
                Value.status = Define.ItemBuyStatus.Unlock
                break
            end
        end
    end

    player.property:changeFitnessEquipId(itemId, nextUnlockItemId)

end

