function GameFitnessEquip:initAdvancedFitnessEquipItem(player)
    local i = 1
    local itemId = -1
    local data = {}
    local flag = false

    table.sort(player.shopFitnessEquip, function(a, b)
        return FitnessEquipConfig:getFitnessEquipSortId(a.id) < FitnessEquipConfig:getFitnessEquipSortId(b.id)
    end)

    for _, Value in pairs(player.shopFitnessEquip) do
        local config = FitnessEquipConfig:getFitnessEquipConfig(Value.id)
        if (Value.status == Define.ItemBuyStatus.Buy or Value.status == Define.ItemBuyStatus.Used)
                and (config.moneyType == Define.MoneyType.DiamondGolds2 or config.moneyType == Define.MoneyType.DiamondGolds1)
                and flag == false then
            flag = true
            itemId = Value.id
        end

        if (Value.status == Define.ItemBuyStatus.Buy or Value.status == Define.ItemBuyStatus.Used)
                and FitnessEquipConfig:isPayFitnessEquip(Value.id) then
            flag = true
            itemId = Value.id
        end

        --������������
        if FitnessEquipConfig:isPayFitnessEquip(Value.id) then
            local payConfig = FitnessEquipConfig:getPayFitnessEquipConfig(Value.id)
            if payConfig and player.property.advancedLevel >= payConfig.unlockAdvancedLevel and Value.status == Define.ItemBuyStatus.Lock then
                Value.status = Define.ItemBuyStatus.Unlock
                table.insert(data, {
                    Id = Value.id,
                    Status = Value.status
                })
            end
        end
    end

    if flag == false then
        for _, Value in pairs(player.shopFitnessEquip) do
            local config = FitnessEquipConfig:getFitnessEquipConfig(Value.id)
            if i == 1 then
                Value.status = Define.ItemBuyStatus.Used
                itemId = Value.id
                table.insert(data, {
                    Id = Value.id,
                    Status = Value.status
                })
            elseif Value.status ~= Define.ItemBuyStatus.Lock and
                    (config.moneyType ~= Define.MoneyType.DiamondGolds1 and config.moneyType ~= Define.MoneyType.DiamondGolds2) then
                Value.status = Define.ItemBuyStatus.Unlock
                table.insert(data, {
                    Id = Value.id,
                    Status = Value.status
                })
            elseif Value.status == Define.ItemBuyStatus.Used  and
                    (config.moneyType == Define.MoneyType.DiamondGolds1 or config.moneyType == Define.MoneyType.DiamondGolds2) then
                Value.status = Define.ItemBuyStatus.Buy
                table.insert(data, {
                    Id = Value.id,
                    Status = Value.status
                })
            end
            i = i + 1
        end
    else
        for _, Value in pairs(player.shopFitnessEquip) do
            local config = FitnessEquipConfig:getFitnessEquipConfig(Value.id)
            if Value.id == itemId then
                Value.status = Define.ItemBuyStatus.Used
                table.insert(data, {
                    Id = Value.id,
                    Status = Value.status
                })
            elseif i == 1 then
                Value.status = Define.ItemBuyStatus.Buy
                table.insert(data, {
                    Id = Value.id,
                    Status = Value.status
                })
            elseif Value.status ~= Define.ItemBuyStatus.Lock and
                    (config.moneyType ~= Define.MoneyType.DiamondGolds1 and config.moneyType ~= Define.MoneyType.DiamondGolds2) then
                Value.status = Define.ItemBuyStatus.Unlock
                table.insert(data, {
                    Id = Value.id,
                    Status = Value.status
                })
            elseif Value.status == Define.ItemBuyStatus.Used  and
                    (config.moneyType == Define.MoneyType.DiamondGolds1 or config.moneyType == Define.MoneyType.DiamondGolds2) then
                Value.status = Define.ItemBuyStatus.Buy
                table.insert(data, {
                    Id = Value.id,
                    Status = Value.status
                })
            end
            i = i + 1
        end
    end

    local nextUnlockItemId = nil
    for _, Value in pairs(player.shopFitnessEquip) do
        local equip = FitnessEquipConfig:getFitnessEquipConfig(Value.id)
        if equip and equip.unlock == itemId then
            nextUnlockItemId = equip.id
        end
    end

    if itemId ~= -1 then
        player.property:changeFitnessEquipId(itemId, nextUnlockItemId)
    end

    GameFitnessEquip:shareDataToTokenFitnessEquip(player, data)
    ShopManager:senderFitnessEquipInfo(player, data)
end

function GameFitnessEquip:shareDataToTokenFitnessEquip(player, data, isUsedChange)
    local info = {}
    if not isUsedChange then
        for k, v in pairs(player.tokenShopFitnessEquip) do
            if v.status == Define.TokenItemBuyStatus.Used then
                v.status = Define.TokenItemBuyStatus.Buy
                table.insert(info, {
                    Id = v.id,
                    Status = v.status
                })
            end
        end
    end

    for _, value in pairs(data) do
        for k, v in pairs(player.tokenShopFitnessEquip) do
            if value.Id == v.id then
                v.status = value.Status
                table.insert(info, {
                    Id = value.Id,
                    Status = value.Status
                })
            end

            if value.Status == Define.TokenItemBuyStatus.Buy or value.Status == Define.TokenItemBuyStatus.Used then
                local equip = TokenFitnessEquipConfig:getFitnessEquipConfig(v.id)
                if equip and equip.unlock == value.Id and v.status == Define.ItemBuyStatus.Lock and player.property.advancedLevel >= equip.advancedId  then
                    v.status = Define.ItemBuyStatus.Unlock
                    table.insert(info, {
                        Id = v.id,
                        Status = v.status
                    })
                end
            end
        end
    end
    TokenShopManager:senderTokenFitnessEquipInfo(player, info)
end

return GameFitnessEquip